52	// ── Mic level thread ─────────────────────────────────────────────────────────
53	
54	/// Shared mic level state: f32 RMS stored as bits in an AtomicU32.
55	struct MicLevelState {
56	    level: Arc<AtomicU32>,
57	    no_device: bool,
58	    _handle: Option<std::thread::JoinHandle<()>>,
59	}
60	
61	impl MicLevelState {
62	    fn current_level(&self) -> f32 {
63	        f32::from_bits(self.level.load(Ordering::Relaxed))
64	    }
65	}
66	
67	fn spawn_mic_level_thread() -> MicLevelState {
68	    let level = Arc::new(AtomicU32::new(0u32));
69	    let level_clone = Arc::clone(&level);
70	
71	    // no_device is signalled back from the thread via a one-shot channel.
72	    let (tx, rx) = std::sync::mpsc::sync_channel::<bool>(1);
73	
74	    // Build and play the stream inside the thread so the !Send stream never
75	    // crosses a thread boundary.
76	    let handle = std::thread::spawn(move || {
77	        use cpal::traits::{DeviceTrait, HostTrait, StreamTrait};
78	
79	        let host = cpal::default_host();
80	        let device = match host.default_input_device() {
81	            Some(d) => d,
82	            None => {
83	                tracing::warn!("Mic level: no default input device found");
84	                let _ = tx.send(true);
85	                return;
86	            }
87	        };
88	
89	        let config = match device.default_input_config() {
90	            Ok(c) => c,
91	            Err(e) => {
92	                tracing::error!(reason = %e, "Mic level: failed to get default input config");
93	                let _ = tx.send(true);
94	                return;
95	            }
96	        };
97	
98	        tracing::info!(
99	            device = device.name().unwrap_or_default(),
100	            sample_rate = config.sample_rate().0,
101	            channels = config.channels(),
102	            "Mic level thread: using device"
103	        );
104	
105	        let err_level = Arc::clone(&level_clone);
106	        let stream_result = device.build_input_stream(
107	            &config.into(),
108	            move |data: &[f32], _| {
109	                if data.is_empty() {
110	                    return;
111	                }
112	                let rms = (data.iter().map(|s| s * s).sum::<f32>() / data.len() as f32).sqrt();
113	                level_clone.store(rms.to_bits(), Ordering::Relaxed);
114	            },
115	            move |e| {
116	                tracing::error!(reason = %e, "Mic level: stream error");
117	                err_level.store(0u32, Ordering::Relaxed);
118	            },
119	            None,
120	        );
121	
122	        let stream = match stream_result {
123	            Ok(s) => s,
124	            Err(e) => {
125	                tracing::error!(reason = %e, "Mic level: failed to build input stream");
126	                let _ = tx.send(true);
127	                return;
128	            }
129	        };
130	
131	        if let Err(e) = stream.play() {
132	            tracing::error!(reason = %e, "Mic level: stream play failed");
133	            let _ = tx.send(true);
134	            return;
135	        }
136	
137	        let _ = tx.send(false);
138	        // Park the thread to keep the stream alive until the process exits.
139	        std::thread::park();
140	    });
141	
142	    let no_device = rx.recv().unwrap_or(true);
143	
144	    MicLevelState {
145	        level,
146	        no_device,
147	        _handle: Some(handle),
148	    }
149	}
